<template>
  <view class="page">
    <!-- 背景装饰 -->
    <view class="bg-grid"></view>
    <view class="bg-glow bg-glow-1"></view>
    <view class="bg-glow bg-glow-2"></view>
    <view class="bg-glow bg-glow-3"></view>

    <!-- 头部 -->
    <view class="header">
      <view class="header-left">
        <view class="header-title-row">
          <image class="header-icon" src="data:image/svg+xml;base64," mode="aspectFit" />
          <text class="header-title">积金罐</text>
        </view>
        <text class="header-subtitle">每日积金，收益满罐</text>
      </view>
    </view>

    <!-- 折叠后的迷你统计条 -->
    <view class="mini-stats-bar" v-if="(currentTab === 'holdings' && isCardsCollapsed)">
      <view class="mini-stat-item">
        <text class="mini-stat-label">总资产</text>
        <text class="mini-stat-value">{{ formatMoney(stats.totalAmount) }}</text>
      </view>
      <view class="mini-stat-divider"></view>
      <view class="mini-stat-item">
        <text class="mini-stat-label">今日盈亏</text>
        <text class="mini-stat-value" :class="stats.todayProfit >= 0 ? 'red' : 'green'">
          {{ formatMoney(stats.todayProfit, true) }}
        </text>
      </view>
      <view class="mini-stat-divider"></view>
      <view class="mini-stat-item">
        <text class="mini-stat-label">累计收益</text>
        <text class="mini-stat-value" :class="stats.totalProfit >= 0 ? 'red' : 'green'">
          {{ formatMoney(stats.totalProfit, true) }}
        </text>
      </view>
    </view>

    <!-- 统计卡片 Bento Grid -->
    <view class="bento-grid-wrapper" :class="{ 'bento-grid-collapsed': currentTab === 'watchlist' || isCardsCollapsed }">
      <view class="bento-grid">
        <!-- 总资产 -->
      <view class="amount-card">
        <!-- #ifdef H5 -->
        <view id="lottie-canvas" class="lottie-canvas"></view>
        <!-- #endif -->
        <!-- #ifdef MP-WEIXIN -->
        <canvas id="lottie-canvas" type="2d" class="lottie-canvas"></canvas>
        <!-- #endif -->
        <view class="amount-title">
          <view class="coin">
            <view class="side heads">
              <svg xmlns="http://www.w3.org/2000/svg" xml:space="preserve" width="100%" height="100%" version="1.1" shape-rendering="geometricPrecision" text-rendering="geometricPrecision" image-rendering="optimizeQuality" fill-rule="evenodd" clip-rule="evenodd" viewBox="0 0 4091.27 4091.73" xmlns:xlink="http://www.w3.org/1999/xlink">
                <g id="Layer_x0020_1">
                  <metadata id="CorelCorpID_0Corel-Layer"></metadata>
                  <g id="_1421344023328">
                    <path fill="#F7931A" fill-rule="nonzero" d="M4030.06 2540.77c-273.24,1096.01 -1383.32,1763.02 -2479.46,1489.71 -1095.68,-273.24 -1762.69,-1383.39 -1489.33,-2479.31 273.12,-1096.13 1383.2,-1763.19 2479,-1489.95 1096.06,273.24 1763.03,1383.51 1489.76,2479.57l0.02 -0.02z"></path>
