      arrowUpSvg: 'data:image/svg+xml,%3Csvg%20viewBox%3D%220%200%2024%2024%22%20fill%3D%22none%22%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20transform%3D%22matrix%281%2C%200%2C%200%2C%20-1%2C%200%2C%200%29%22%3E%3Cg%20id%3D%22SVGRepo_bgCarrier%22%20stroke-width%3D%220%22%3E%3C%2Fg%3E%3Cg%20id%3D%22SVGRepo_tracerCarrier%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%3E%3C%2Fg%3E%3Cg%20id%3D%22SVGRepo_iconCarrier%22%3E%20%3Cg%20clip-path%3D%22url%28%23clip0_1076_36063%29%22%3E%20%3Cpath%20d%3D%22M12.4393%207.43933L8.49996%2011.3787L2.76773%205.64644C2.3772%205.25592%201.74404%205.25592%201.35352%205.64644L0.646409%206.35355C0.255885%206.74407%200.255885%207.37724%200.646409%207.76776L7.4393%2014.5607C8.02509%2015.1464%208.97484%2015.1464%209.56062%2014.5607L13.5%2010.6213L18.2322%2015.3535L16.2928%2017.2929C16.0068%2017.5789%2015.9212%2018.009%2016.076%2018.3827C16.2308%2018.7564%2016.5954%2019%2016.9999%2019H22.9999C23.5522%2019%2023.9999%2018.5523%2023.9999%2018V12C23.9999%2011.5955%2023.7562%2011.2309%2023.3826%2011.0761C23.0089%2010.9213%2022.5788%2011.0069%2022.2928%2011.2929L20.3535%2013.2322L14.5606%207.43933C13.9748%206.85355%2013.0251%206.85355%2012.4393%207.43933Z%22%20fill%3D%22%23cf203b%22%3E%3C%2Fpath%3E%20%3C%2Fg%3E%20%3Cdefs%3E%20%3CclipPath%20id%3D%22clip0_1076_36063%22%3E%20%3Crect%20width%3D%2224%22%20height%3D%2224%22%20fill%3D%22white%22%3E%3C%2Frect%3E%20%3C%2FclipPath%3E%20%3C%2Fdefs%3E%20%3C%2Fg%3E%3C%2Fsvg%3E',
      arrowDownSvg: 'data:image/svg+xml,%3Csvg%20viewBox%3D%220%200%2024%2024%22%20fill%3D%22none%22%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%3E%3Cg%20id%3D%22SVGRepo_bgCarrier%22%20stroke-width%3D%220%22%3E%3C%2Fg%3E%3Cg%20id%3D%22SVGRepo_tracerCarrier%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%3E%3C%2Fg%3E%3Cg%20id%3D%22SVGRepo_iconCarrier%22%3E%20%3Cg%20clip-path%3D%22url(%23clip0_1076_36063)%22%3E%20%3Cpath%20d%3D%22M12.4393%207.43933L8.49996%2011.3787L2.76773%205.64644C2.3772%205.25592%201.74404%205.25592%201.35352%205.64644L0.646409%206.35355C0.255885%206.74407%200.255885%207.37724%200.646409%207.76776L7.4393%2014.5607C8.02509%2015.1464%208.97484%2015.1464%209.56062%2014.5607L13.5%2010.6213L18.2322%2015.3535L16.2928%2017.2929C16.0068%2017.5789%2015.9212%2018.009%2016.076%2018.3827C16.2308%2018.7564%2016.5954%2019%2016.9999%2019H22.9999C23.5522%2019%2023.9999%2018.5523%2023.9999%2018V12C23.9999%2011.5955%2023.7562%2011.2309%2023.3826%2011.0761C23.0089%2010.9213%2022.5788%2011.0069%2022.2928%2011.2929L20.3535%2013.2322L14.5606%207.43933C13.9748%206.85355%2013.0251%206.85355%2012.4393%207.43933Z%22%20fill%3D%22%2316a34a%22%3E%3C%2Fpath%3E%20%3C%2Fg%3E%20%3Cdefs%3E%20%3CclipPath%20id%3D%22clip0_1076_36063%22%3E%20%3Crect%20width%3D%2224%22%20height%3D%2224%22%20fill%3D%22white%22%3E%3C%2Frect%3E%20%3C%2FclipPath%3E%20%3C%2Fdefs%3E%20%3C%2Fg%3E%3C%2Fsvg%3E',
      // 板块筛选
      selectedSector: 'all',
      sectorTabs: []
    }
  },
  computed: {
    formatMoney() {
      return formatMoney
    },
    formatPercent() {
      return formatPercent
    },
    currentSortLabel() {
      const option = this.sortOptions.find(o => o.value === this.sortType)
      return option ? option.label : '总涨跌幅'
    },
    watchlistWithEstimate() {
      return this.watchlist.map(item => ({
        ...item,
        todayRate: this.watchlistEstimates[item.fundCode]?.todayRate || 0,
        todayProfit: this.watchlistEstimates[item.fundCode]?.todayProfit || 0
      }))
    },
    filteredHoldings() {
      if (this.selectedSector === 'all') {
        return this.holdings
      }
      return this.holdings.filter(holding => {
        const sectors = holding.sectors || []
        return sectors.includes(this.selectedSector)
      })
    }
  },
  onShow() {
    this.loadData()
    // #ifdef H5
    // 禁用H5页面滚动
    // document.body.style.overflow = 'hidden'
    // document.documentElement.style.overflow = 'hidden'
    // #endif
  },
  onReady() {
    this.initLottie()
    // 键盘快速定位：非响应式内部状态（不触发渲染）
    this._keyBuffer = ''
    this._keyTimer = null
    this._holdingCurrentScrollTop = 0
    this._watchCurrentScrollTop = 0
    // #ifdef H5
    this._keyHandler = this.onGlobalKeyDown.bind(this)
    document.addEventListener('keydown', this._keyHandler)
    // #endif
  },
  onHide() {
    // #ifdef H5
    if (this._keyHandler) {
      document.removeEventListener('keydown', this._keyHandler)
      this._keyHandler = null
    }
    // 恢复滚动
    // document.body.style.overflow = ''
    // document.documentElement.style.overflow = ''
    // #endif
  },
  onPullDownRefresh() {
    this.refreshAll()
  },
  methods: {
    initLottie() {
      // #ifdef H5
      // H5环境使用lottie-web
      import('lottie-web').then(lottie => {
        Promise.all([
          import('@/static/icons/piggy-saving.json'),
          import('@/static/icons/stock.json'),
          import('@/static/icons/rollup.json'),
          import('@/static/icons/del_arrow.json'),
          import('@/static/icons/search_zx3.json')
        ]).then(([piggySavingData, stockData, rollupData, delArrowData, searchZx3Data]) => {
          // 加载 piggy-saving 动画
          lottie.default.loadAnimation({
            container: document.getElementById('lottie-canvas'),
            renderer: 'svg',
            loop: true,
            autoplay: true,
            animationData: piggySavingData.default
          })

          // 加载 stock 动画
          lottie.default.loadAnimation({
            container: document.getElementById('stock-lottie-canvas'),
            renderer: 'svg',
            loop: true,
            autoplay: true,
            animationData: stockData.default
          })

          // 加载 rollup 动画
          lottie.default.loadAnimation({
            container: document.getElementById('rollup-lottie-canvas'),
            renderer: 'svg',
            loop: false,
            autoplay: false,
            animationData: rollupData.default
          })

          this.initWatchSwipeHintLottieH5(lottie.default, delArrowData.default)

          // 加载 search-zx3 搜索动画
          const searchEl = document.getElementById('search-lottie-canvas')
          if (searchEl) {
            lottie.default.loadAnimation({
              container: searchEl,
              renderer: 'svg',
              loop: true,
              autoplay: true,
              animationData: searchZx3Data.default
            })
          }
        }).catch(err => {
          console.error('加载lottie动画失败:', err)
        })
      })
      // #endif
      
      // #ifdef MP-WEIXIN
      const query = uni.createSelectorQuery().in(this)
      query.select('#lottie-canvas')
        .fields({ node: true, size: true })
        .exec((res) => {
          if (res && res[0]) {
            const canvas = res[0].node
            const ctx = canvas.getContext('2d')
            
            const dpr = 3  // 提高清晰度
            canvas.width = 120 * dpr
            canvas.height = 120 * dpr
            ctx.scale(dpr, dpr)
            
            // 加载lottie动画数据
            uni.request({
              url: '/static/icons/piggy-saving.json',
              success: (response) => {
                const lottie = require('lottie-miniprogram')
                lottie.loadAnimation({
                  loop: true,
                  autoplay: true,
                  animationData: response.data,
                  rendererSettings: {
                    context: ctx,
                    canvas: canvas,
                    clearCanvas: true
                  }
                })
              },
              fail: (err) => {
                console.error('加载lottie动画失败:', err)
              }
            })
          }
        })
      
      // 加载stock.json动画（微信小程序）
      const stockQuery = uni.createSelectorQuery().in(this)
      stockQuery.select('#stock-lottie-canvas')
        .fields({ node: true, size: true })
        .exec((res) => {
          if (res && res[0]) {
            const canvas = res[0].node
            const ctx = canvas.getContext('2d')
            
            const dpr = 3
            canvas.width = 80 * dpr
            canvas.height = 80 * dpr
            ctx.scale(dpr, dpr)
            
            uni.request({
              url: '/static/icons/stock.json',
              success: (response) => {
                const lottie = require('lottie-miniprogram')
                lottie.loadAnimation({
                  loop: true,
                  autoplay: true,
                  animationData: response.data,
                  rendererSettings: {
                    context: ctx,
                    canvas: canvas,
                    clearCanvas: true
                  }
                })
              },
              fail: (err) => {
                console.error('加载stock动画失败:', err)
              }
            })
          }
        })
      
      // 加载rollup.json动画（微信小程序）
      const rollupQuery = uni.createSelectorQuery().in(this)
      rollupQuery.select('#rollup-lottie-canvas')
        .fields({ node: true, size: true })
        .exec((res) => {
          if (res && res[0]) {
            const canvas = res[0].node
            const ctx = canvas.getContext('2d')

            const dpr = 3
            canvas.width = 48 * dpr
            canvas.height = 48 * dpr
            ctx.scale(dpr, dpr)

            uni.request({
              url: '/static/icons/rollup.json',
              success: (response) => {
                const lottie = require('lottie-miniprogram')
                lottie.loadAnimation({
                  loop: false,
                  autoplay: false,
                  animationData: response.data,
                  rendererSettings: {
                    context: ctx,
                    canvas: canvas,
                    clearCanvas: true
                  }
                })
              },
              fail: (err) => {
                console.error('加载rollup动画失败:', err)
              }
            })
          }
        })

      uni.request({
        url: '/static/icons/del_arrow.json',
        success: (response) => {
          this.initWatchSwipeHintLottieMp(response.data)
        },
        fail: (err) => {
          console.error('加载del_arrow动画失败:', err)
        }
      })

      // 加载search_zx3.json动画（微信小程序）
      const searchQuery = uni.createSelectorQuery().in(this)
      searchQuery.select('#search-lottie-canvas')
        .fields({ node: true, size: true })
        .exec((res) => {
          if (res && res[0]) {
            const canvas = res[0].node
            const ctx = canvas.getContext('2d')

            const dpr = 3
            canvas.width = 48 * dpr
            canvas.height = 48 * dpr
            ctx.scale(dpr, dpr)

            uni.request({
              url: '/static/icons/search_zx3.json',
              success: (response) => {
                const lottie = require('lottie-miniprogram')
                lottie.loadAnimation({
                  loop: true,
                  autoplay: true,
                  animationData: response.data,
                  rendererSettings: {
                    context: ctx,
                    canvas: canvas,
                    clearCanvas: true
                  }
                })
              },
              fail: (err) => {
                console.error('加载search_zx3动画失败:', err)
              }
            })
          }
        })
      // #endif
    },

    initWatchSwipeHintLottieH5(lottie, animationData) {
      this.$nextTick(() => {
        const ids = this.watchlist.map(item => `watch-del-arrow-${item.id}`)
        ids.forEach(id => {
          const container = document.getElementById(id)
          if (!container || container.dataset.lottieReady === '1') return
          lottie.loadAnimation({
            container,
            renderer: 'svg',
            loop: true,
            autoplay: true,
            animationData
          })
          container.dataset.lottieReady = '1'
        })
      })
    },

    initWatchSwipeHintLottieMp(animationData) {
      this.$nextTick(() => {
        const lottie = require('lottie-miniprogram')
        this.watchlist.forEach(item => {
          const query = uni.createSelectorQuery().in(this)
          query.select(`#watch-del-arrow-${item.id}`)
            .fields({ node: true, size: true })
            .exec((res) => {
              if (!res || !res[0] || !res[0].node) return
              const canvas = res[0].node
              if (canvas.__watchArrowReady) return
              const ctx = canvas.getContext('2d')
              const dpr = 2
              canvas.width = 56 * dpr
              canvas.height = 56 * dpr
              ctx.scale(dpr, dpr)
              lottie.loadAnimation({
                loop: true,
                autoplay: true,
                animationData,
                rendererSettings: {
                  context: ctx,
                  canvas,
                  clearCanvas: true
                }
              })
              canvas.__watchArrowReady = true
            })
        })
      })
    },
    
    switchTab(tab) {
      this.currentTab = tab
      this.closeAllWatchSwipes()
      if (tab === 'watchlist' && this.watchlist.length > 0) {
        this.refreshWatchlistEstimates()
      }
    },

    getWatchDeleteWidth() {
      return 132
    },

    getTouchPoint(e) {
      const point = (e.changedTouches && e.changedTouches[0]) || (e.touches && e.touches[0]) || e
      return {
        x: point?.clientX ?? 0,
        y: point?.clientY ?? 0
      }
    },

    getWatchCardStyle(id) {
      const offset = this.watchSwipeOffsets[id] || 0
      return `transform: translateX(${offset}rpx);`
    },

    getWatchDeleteActionStyle(id) {
      const deleteWidth = this.getWatchDeleteWidth()
      const offset = Math.abs(this.watchSwipeOffsets[id] || 0)
      const progress = Math.max(0, Math.min(1, offset / deleteWidth))
      const opacity = 0.18 + progress * 0.82
      const scale = 0.95 + progress * 0.05
      const iconOpacity = 0.35 + progress * 0.65
      const iconScale = 0.9 + progress * 0.1
      return `opacity: ${opacity}; transform: scale(${scale}); --delete-icon-opacity: ${iconOpacity}; --delete-icon-scale: ${iconScale};`
    },
    closeWatchSwipe(id) {
      if (!id) return
      this.watchSwipeOffsets = {
        ...this.watchSwipeOffsets,
        [id]: 0
      }
      if (this.watchSwipeOpenId === id) {
        this.watchSwipeOpenId = ''
      }
    },

    closeAllWatchSwipes() {
      if (!this.watchSwipeOpenId && Object.keys(this.watchSwipeOffsets).length === 0) return
      const reset = {}
      Object.keys(this.watchSwipeOffsets).forEach(id => {
        reset[id] = 0
      })
      this.watchSwipeOffsets = reset
      this.watchSwipeOpenId = ''
      this.watchTouchState = {
        activeId: '',
        startX: 0,
        startY: 0,
        startOffset: 0,
        currentOffset: 0,
        isSwiping: false,
        didMove: false,
        lockDirection: ''
      }
    },

    handleWatchCardTap(item) {
      if (this.watchTouchState.didMove) {
        this.watchTouchState.didMove = false
        return
      }

      if (this.watchSwipeOpenId) {
        this.closeAllWatchSwipes()
        return
      }

      this.goDetail(item)
    },

    onWatchTouchStart(item, e) {
      const point = this.getTouchPoint(e)
      const activeId = item.id
      const currentOffset = this.watchSwipeOffsets[activeId] || 0

      if (this.watchSwipeOpenId && this.watchSwipeOpenId !== activeId) {
        this.closeAllWatchSwipes()
      }

      this.watchTouchState = {
        activeId,
        startX: point.x,
        startY: point.y,
        startOffset: currentOffset,
        currentOffset,
        isSwiping: false,
        didMove: false,
        lockDirection: ''
      }
    },

    onWatchTouchMove(item, e) {
      if (this.watchTouchState.activeId !== item.id) return

      const point = this.getTouchPoint(e)
      const deltaX = point.x - this.watchTouchState.startX
      const deltaY = point.y - this.watchTouchState.startY
      const absX = Math.abs(deltaX)
      const absY = Math.abs(deltaY)

      if (!this.watchTouchState.lockDirection) {
        if (absX < 8 && absY < 8) return
        this.watchTouchState.lockDirection = absX > absY ? 'horizontal' : 'vertical'
      }

      if (this.watchTouchState.lockDirection !== 'horizontal') return

      const deleteWidth = this.getWatchDeleteWidth()
      const nextOffset = Math.min(0, Math.max(-deleteWidth, this.watchTouchState.startOffset + deltaX))
      this.watchTouchState.isSwiping = true
      this.watchTouchState.didMove = true
      this.watchTouchState.currentOffset = nextOffset
      this.watchSwipeOffsets = {
        ...this.watchSwipeOffsets,
        [item.id]: nextOffset
      }
    },

    onWatchTouchEnd(item) {
      if (this.watchTouchState.activeId !== item.id) return

      if (this.watchTouchState.lockDirection !== 'horizontal' || !this.watchTouchState.isSwiping) {
        this.watchTouchState.activeId = ''
        return
      }

      const deleteWidth = this.getWatchDeleteWidth()
      const threshold = deleteWidth * 0.4
      const currentOffset = this.watchTouchState.currentOffset
      const shouldOpen = Math.abs(currentOffset) > threshold
      const finalOffset = shouldOpen ? -deleteWidth : 0

      this.watchSwipeOffsets = {
        ...this.watchSwipeOffsets,
        [item.id]: finalOffset
      }
      this.watchSwipeOpenId = shouldOpen ? item.id : ''
      this.watchTouchState.activeId = ''
      this.watchTouchState.currentOffset = finalOffset
      this.watchTouchState.isSwiping = false
    },

    onWatchTouchCancel(item) {
      if (this.watchTouchState.activeId !== item.id) return
      if (this.watchSwipeOpenId === item.id) {
        this.watchSwipeOffsets = {
          ...this.watchSwipeOffsets,
          [item.id]: -this.getWatchDeleteWidth()
        }
      } else {
        this.closeWatchSwipe(item.id)
      }
      this.watchTouchState.activeId = ''
      this.watchTouchState.isSwiping = false
    },

    toggleCardsCollapse() {
      this.isCardsCollapsed = !this.isCardsCollapsed
    },
    
    async loadData() {
      this.holdings = getHoldings()
      this.watchlist = getWatchlist()
      this.closeAllWatchSwipes()
      this.calculateTotalStats()
      this.updateSectorTabs()

      if (this.holdings.length > 0) {
        await this.refreshAll()
      }

      // #ifdef H5
      import('lottie-web').then(lottie => {
        import('@/static/icons/del_arrow.json').then(delArrowData => {
          this.initWatchSwipeHintLottieH5(lottie.default, delArrowData.default)
        })
      })
      // #endif

      // #ifdef MP-WEIXIN
      uni.request({
        url: '/static/icons/del_arrow.json',
        success: (response) => {
          this.initWatchSwipeHintLottieMp(response.data)
        }
      })
      // #endif
    },
    
    calculateTotalStats() {
      this.stats = calculateStats(this.holdings)
    },
    
    async refreshAll() {
      await Promise.all([
        this.refreshEstimates(),
        this.refreshFundSectors()
      ])
      uni.stopPullDownRefresh()
    },

    async refreshFundSectors() {
      try {
        const codes = this.holdings.map(h => h.fundCode)
        console.log('[refreshFundSectors] 获取板块信息, codes:', codes)
        const fundInfos = await getFundSectorsBatch(codes)
        console.log('[refreshFundSectors] 返回结果:', fundInfos)

        const sectorsMap = {}
        fundInfos.forEach(info => {
          if (info && info.code) {
            sectorsMap[info.code] = info.sectors || []
          }
        })

        this.holdings.forEach(holding => {
          holding.sectors = sectorsMap[holding.fundCode] || ['混合']
        })

        this.updateSectorTabs()
      } catch (e) {
        console.error('刷新基金板块失败:', e)
      }
    },

    updateSectorTabs() {
      const sectorCount = {}
      this.holdings.forEach(holding => {
        const sectors = holding.sectors || []
        sectors.forEach(sector => {
          sectorCount[sector] = (sectorCount[sector] || 0) + 1
        })
      })

      const tabs = Object.entries(sectorCount)
        .map(([sector, count]) => ({
          name: sector,
          count
        }))
        .sort((a, b) => b.count - a.count)

      this.sectorTabs = tabs

      if (this.selectedSector === 'all' && tabs.length === 0) {
        this.selectedSector = 'all'
      } else if (this.selectedSector !== 'all' && !tabs.find(t => t.name === this.selectedSector)) {
        this.selectedSector = 'all'
      }
    },

    selectSector(sector) {
      this.selectedSector = sector
    },
    
    async refreshEstimates() {
      try {
        const codes = this.holdings.map(h => h.fundCode)
        const estimates = await getFundEstimates(codes)
        
        const settings = getNotificationSettings()
        
        estimates.forEach((est, index) => {
          if (est && this.holdings[index]) {
            const rate = parseFloat(est.estimatedPercent) || 0
            const amount = parseFloat(this.holdings[index].amount) || 0
            this.holdings[index].todayProfit = (amount * rate / 100).toFixed(2)
            this.holdings[index].todayRate = rate
            this.holdings[index].estimateTimeDesc = est.timeDesc || ''

            if (settings.enabled && settings.profitAlert) {
              generateProfitAlert(this.holdings[index], rate)
            }
          }
        })
        
        this.calculateTotalStats()
        
        if (settings.enabled && settings.dailyReport) {
          generateDailyReport(this.stats)
        }
      } catch (e) {
        console.error('刷新估值失败:', e)
      }
    },
    
    goAdd() {
      uni.navigateTo({
        url: '/pages/add/add'
      })
    },
    
    editHolding(item) {
      uni.navigateTo({
        url: `/pages/add/add?id=${item.id}`
      })
    },
    
    goDetail(item) {
      uni.navigateTo({
        url: `/pages/detail/detail?code=${item.fundCode}&name=${encodeURIComponent(item.fundName || '未命名基金')}`
      })
    },

    handleNote(item) {
      this.noteTarget = item
      this.noteInput = item.note || ''
      this.showNoteModal = true
    },

    cancelNote() {
      this.showNoteModal = false
      this.noteTarget = null
      this.noteInput = ''
    },

    async confirmNote() {
      if (!this.noteTarget) return
      const id = this.noteTarget.id
      const note = (this.noteInput || '').trim()
      try {
        await updateHolding(id, { note })
        const target = this.holdings.find(h => h.id === id)
        if (target) target.note = note
        this.showNoteModal = false
        this.noteTarget = null
        this.noteInput = ''
        uni.showToast({ title: '已保存', icon: 'success' })
      } catch (e) {
        console.error('保存备注失败:', e)
        uni.showToast({ title: '保存失败', icon: 'none' })
      }
    },
    
    toggleSortDropdown() {
      if (this.showSortDropdown) {
        this.showSortDropdown = false
        return
      }
      // 获取 sort-picker 的位置来定位下拉菜单
      const query = uni.createSelectorQuery().in(this)
      query.select('.sort-picker').boundingClientRect()
      query.exec((res) => {
        if (res && res[0]) {
          const rect = res[0]
          this.sortDropdownTop = (rect.bottom + 6) + 'px'
          // 计算右边距：窗口宽度 - 元素右边缘
          const sysInfo = uni.getSystemInfoSync()
          this.sortDropdownRight = (sysInfo.windowWidth - rect.right) + 'px'
        }
        this.showSortDropdown = true
      })
    },
    closeSortDropdown() {
      this.showSortDropdown = false
    },
    onSortDropdownSelect(item) {
      this.sortType = item.value
      this.showSortDropdown = false
      this.sortHoldings()
    },
    
    toggleSortOrder() {
      this.sortOrder = this.sortOrder === 'up' ? 'down' : 'up'
      this.sortHoldings()
    },
    
    sortHoldings() {
      const multiplier = this.sortOrder === 'up' ? 1 : -1
      this.holdings.sort((a, b) => {
        if (this.sortType === 'today') {
          const rateA = parseFloat(a.todayRate) || 0
          const rateB = parseFloat(b.todayRate) || 0
          return (rateA - rateB) * multiplier
        } else {
          const rateA = a.amount > 0 ? (a.profit / a.amount) : 0
          const rateB = b.amount > 0 ? (b.profit / b.amount) : 0
          return (rateA - rateB) * multiplier
        }
      })
    },
    
    handleDeleteHolding(item) {
      this.deleteTarget = item
      this.showDeleteModal = true
    },
    
    cancelDelete() {
      this.showDeleteModal = false
      this.deleteTarget = null
    },

    handleDeleteAll() {
      this.deleteTarget = { fundName: '所有持仓基金' }
      this.showDeleteModal = true
    },

    handleDeleteAllWatch() {
      this.deleteTarget = { fundName: '所有自选基金' }
      this.showDeleteModal = true
    },

    async confirmDeleteAction() {
      if (!this.deleteTarget) return

      const isDeleteAll = this.deleteTarget.fundName === '所有持仓基金'
      const isDeleteAllWatch = this.deleteTarget.fundName === '所有自选基金'

      this.showDeleteModal = false
      uni.showLoading({ title: '删除中...' })
      try {
        if (isDeleteAll) {
          const holdingsToDelete = [...this.holdings]
          for (const holding of holdingsToDelete) {
            await deleteHolding(holding.id)
          }
        } else if (isDeleteAllWatch) {
          saveWatchlist([])
          this.watchlist = []
          this.closeAllWatchSwipes()
        } else {
          await deleteHolding(this.deleteTarget.id)
        }
        uni.hideLoading()
        uni.showToast({
          title: '删除成功',
          icon: 'success'
        })
        this.deleteTarget = null
        if (!isDeleteAllWatch) {
          this.loadData()
        }
      } catch (e) {
        uni.hideLoading()
        uni.showToast({
          title: '删除失败',
          icon: 'none'
        })
        console.error('删除失败:', e)
      }
    },

    formatTodayProfit(value) {
      if (value === null || value === undefined || isNaN(value)) return '--'
      const num = parseFloat(value)
      const formatted = Math.abs(num).toFixed(2)
      if (num >= 0) {
        return `+¥${formatted}`
      } else {
        return `-¥${formatted}`
      }
    },
    
    formatTodayRate(value) {
      if (value === null || value === undefined || isNaN(value)) return '--'
      const num = parseFloat(value)
      return `${num >= 0 ? '+' : ''}${num.toFixed(2)}%`
    },
    
    async refreshWatchlistEstimates() {
      if (this.watchlist.length === 0) return
      
      try {
        const codes = this.watchlist.map(w => w.fundCode)
        const estimates = await getFundEstimates(codes)
        
        estimates.forEach((est, index) => {
          if (est && this.watchlist[index]) {
            const rate = parseFloat(est.estimatedPercent) || 0
            this.watchlistEstimates[this.watchlist[index].fundCode] = {
              todayRate: rate,
              todayProfit: 0
            }
          }
        })
      } catch (e) {
        console.error('刷新自选估值失败:', e)
      }
    },
    
    removeFromWatchlistAction(item) {
      if (this.watchDeletingMap[item.id]) return

      this.watchDeletingMap = {
        ...this.watchDeletingMap,
        [item.id]: true
      }
      this.watchSwipeOpenId = ''
      this.watchSwipeOffsets = {
        ...this.watchSwipeOffsets,
        [item.id]: -this.getWatchDeleteWidth() - 28
      }

      setTimeout(() => {
        removeFromWatchlist(item.id)
        this.watchlist = getWatchlist()
        const nextOffsets = { ...this.watchSwipeOffsets }
        const nextDeletingMap = { ...this.watchDeletingMap }
        delete nextOffsets[item.id]
        delete nextDeletingMap[item.id]
        this.watchSwipeOffsets = nextOffsets
        this.watchDeletingMap = nextDeletingMap
      }, 260)
    },
    
    handleFabClick() {
      if (this.currentTab === 'watchlist') {
        this.openAddWatchModal()
      } else {
        this.goAdd()
      }
    },
    
    goAdd() {
      uni.navigateTo({
        url: '/pages/add/add'
      })
    },
    
    goDetail(item) {
      const code = item.fundCode
      uni.navigateTo({
        url: `/pages/detail/detail?code=${code}&name=${encodeURIComponent(item.fundName || '未命名基金')}`
      })
    },
    
    openAddWatchModal() {
      this.showAddWatchModal = true
      this.watchSearchCode = ''
      this.watchSearchResult = null
      this.watchSearchLoading = false
      this.watchSearchEmpty = false
    },
    
    closeAddWatchModal() {
      // 开始关闭动画
      this.isClosingAddWatch = true
      
      // 等待动画完成后真正关闭
      setTimeout(() => {
        this.showAddWatchModal = false
        this.isClosingAddWatch = false
        this.watchSearchKeyword = ''
        this.watchSearchResults = []
        this.watchSearchLoading = false
        this.watchSearchEmpty = false
      }, 500) // 动画时长 500ms
    },
    
    onWatchSearchInput() {
      if (this.searchTimer) {
        clearTimeout(this.searchTimer)
      }
      this.searchTimer = setTimeout(() => {
        this.searchFundForWatch()
      }, 300)
    },
    
    async searchFundForWatch() {
      const keyword = this.watchSearchKeyword.trim()
      if (!keyword || keyword.length < 2) {
        this.watchSearchResults = []
        this.watchSearchEmpty = false
        return
      }
      
      this.watchSearchLoading = true
      this.watchSearchResults = []
      this.watchSearchEmpty = false
      
      try {
        const results = await searchFund(keyword)
        if (results && results.length > 0) {
          this.watchSearchResults = results.slice(0, 10).map(item => ({
            code: item.fundCode || item.code,
            name: item.fundName || item.name
          }))
        } else {
          this.watchSearchEmpty = true
        }
      } catch (e) {
        console.error('搜索基金失败:', e)
        this.watchSearchEmpty = true
      } finally {
        this.watchSearchLoading = false
      }
    },
    
    async selectWatchFund(item) {
      if (isInWatchlist(item.code)) {
        uni.showToast({
          title: '已在自选中',
          icon: 'none'
        })
        return
      }
      
      const fund = {
        fundCode: item.code,
        fundName: item.name,
        sectors: []
      }
      
      const success = addToWatchlist(fund)
      if (success) {
        this.watchlist = getWatchlist()
        this.closeAddWatchModal()
        uni.showToast({
          title: '添加成功',
          icon: 'success'
        })
        this.refreshWatchlistEstimates()
        
        getFundSectorsBatch([item.code]).then(sectors => {
          if (sectors && sectors[item.code]) {
            const watchlist = getWatchlist()
            const target = watchlist.find(w => w.fundCode === item.code)
            if (target) {
              target.sectors = sectors[item.code]
              saveWatchlist(watchlist)
              this.watchlist = watchlist
            }
          }
        }).catch(e => {
          console.error('后台获取板块失败:', e)
        })
      } else {
        uni.showToast({
          title: '添加失败',
          icon: 'none'
        })
      }
    },
    // 键盘快速定位：全局 keydown 处理
    onGlobalKeyDown(e) {
      // 忽略在 input/textarea 中的键盘输入
      const tag = e.target?.tagName?.toLowerCase()
      if (tag === 'input' || tag === 'textarea') return
      // 忽略组合键
      if (e.ctrlKey || e.altKey || e.metaKey) return

      const key = e.key
      // 只处理数字键（基金代码为纯数字）
      if (/^\d$/.test(key)) {
        e.preventDefault()
        this._keyBuffer += key
        this.onKeyInputChange()
      } else if (key === 'Escape') {
        this.clearKeyInput()
      } else if (key === 'Backspace' && this._keyBuffer.length > 0) {
        e.preventDefault()
        this._keyBuffer = this._keyBuffer.slice(0, -1)
        if (this._keyBuffer.length > 0) {
          this.onKeyInputChange()
        } else {
          this.clearKeyInput()
        }
      }
    },
    onKeyInputChange() {
      const buffer = this._keyBuffer
      // 根据当前 tab 查找匹配的基金
      let matchItem = null
      if (this.currentTab === 'holdings') {
        matchItem = this.holdings.find(h => h.fundCode && h.fundCode.startsWith(buffer))
      } else {
        matchItem = this.watchlist.find(w => w.fundCode && w.fundCode.startsWith(buffer))
      }

      if (matchItem) {
        this.keyInputMatchId = matchItem.id
        this.keyInputHint = buffer + ' → ' + (matchItem.fundName || matchItem.fundCode)
        // 用 createSelectorQuery 精确计算 scrollTop，确保卡片在可见区域最上方
        const isHoldings = this.currentTab === 'holdings'
        const selector = isHoldings ? '#holding-' + matchItem.id : '#watch-' + matchItem.id
        const containerSelector = isHoldings ? '.holding-list' : '.watchlist-container'
        const query = uni.createSelectorQuery().in(this)
        query.select(containerSelector).boundingClientRect()
        query.select(selector).boundingClientRect()
        query.exec((res) => {
          const container = res[0]
          const target = res[1]
          if (container && target) {
            const offset = target.top - container.top
            const scrollTop = (isHoldings ? this._holdingCurrentScrollTop : this._watchCurrentScrollTop) || 0
            const newScrollTop = scrollTop + offset
            // 先清空再设值，确保 scroll-top 变化能触发滚动
            if (isHoldings) {
              this.holdingScrollTop = ''
              this.$nextTick(() => { this.holdingScrollTop = newScrollTop })
            } else {
              this.watchlistScrollTop = ''
              this.$nextTick(() => { this.watchlistScrollTop = newScrollTop })
            }
          }
        })
        // 基金代码完整匹配后，2秒自动清除提示文字和缓冲区
        if (matchItem.fundCode === buffer) {
          if (this._keyTimer) clearTimeout(this._keyTimer)
          this._keyTimer = setTimeout(() => {
            this._keyBuffer = ''
            this.keyInputHint = ''
          }, 2000)
        }
      } else {
        this.keyInputMatchId = ''
        this.keyInputHint = buffer + ' (无匹配)'
        // 无匹配时3秒自动清除，避免残留
        if (this._keyTimer) clearTimeout(this._keyTimer)
        this._keyTimer = setTimeout(() => {
          this._keyBuffer = ''
          this.keyInputHint = ''
        }, 3000)
      }
    },
    clearKeyInput() {
      this._keyBuffer = ''
      this.keyInputHint = ''
      this.keyInputMatchId = ''
      if (this._keyTimer) {
        clearTimeout(this._keyTimer)
        this._keyTimer = null
      }
    },
    onHoldingScroll(e) {
      this._holdingCurrentScrollTop = e.detail.scrollTop
      // 只要用户还在输入中（缓冲区非空），绝不清除任何状态
      if (this._keyBuffer) return
      // 输入已结束后，用户手动滚动才清除高亮
      if (this.keyInputMatchId) {
        this.keyInputMatchId = ''
        this.keyInputHint = ''
      }
    },
    onWatchScroll(e) {
      this._watchCurrentScrollTop = e.detail.scrollTop
      if (this._keyBuffer) return
      if (this.keyInputMatchId) {
        this.keyInputMatchId = ''
        this.keyInputHint = ''
      }
    },
    
    // 搜索持仓基金悬浮按钮
    onSearchFabTap() {
      this.searchFabKeyword = ''
      this.searchFabFocused = true
    },
    onSearchFabInput() {
      const keyword = this.searchFabKeyword.trim()
      if (!keyword) {
        this.keyInputHint = ''
        this.keyInputMatchId = ''
        return
      }
      // 复用键盘快速定位逻辑
      this._keyBuffer = keyword
      this.onKeyInputChange()
    },
    onSearchFabBlur() {
      this.searchFabFocused = false
      // 延迟清除，避免点击搜索结果时blur先触发
      setTimeout(() => {
        if (!this.searchFabFocused) {
          this.searchFabKeyword = ''
        }
      }, 300)
    },
  }
}
</script>

<style lang="scss" scoped>
.page {
  height: 100vh;
  padding: 32rpx;
  position: relative;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
}

.tab-switcher {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16rpx 0;
  margin-bottom: 24rpx;
  position: relative;
  z-index: 10;
  flex-shrink: 0;
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.tab-item {
  position: relative;
  padding: 12rpx 40rpx;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  
  .tab-text {
    font-size: 30rpx;
    color: $text-tertiary;
    font-weight: 500;
    transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);
  }
  
  .tab-indicator {
    position: absolute;
    bottom: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 40rpx;
    height: 6rpx;
    background: linear-gradient(135deg, $accent-terracotta, $accent-gold);
    border-radius: 3rpx;
    animation: tabIndicatorIn 0.5s cubic-bezier(0.4, 0, 0.2, 1);
  }
  
  &.active {
    .tab-text {
      font-size: 36rpx;
      color: $text-primary;
      font-weight: 700;
    }
  }
  
  &:not(.active) {
    .tab-text {
      font-size: 28rpx;
    }
  }
}

@keyframes tabIndicatorIn {
  0% {
    width: 0;
    opacity: 0;
  }
  100% {
    width: 40rpx;
    opacity: 1;
  }
}

.watchlist-section {
  position: relative;
  z-index: 10;
  flex: 1;
  min-height: 0;
  display: flex;
  flex-direction: column;
}

.watchlist-container {
  position: relative;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.watch-swipe-item {
  position: relative;
  margin-bottom: 16rpx;
  border-radius: $radius-lg;
  overflow: hidden;
  transform-origin: center top;
  transition: margin-bottom 0.38s cubic-bezier(0.2, 0.78, 0.24, 1), opacity 0.26s ease;

  &.is-deleting {
    margin-bottom: 0;
    opacity: 0;
    pointer-events: none;
  }

  &--key-match {
    .watch-card {
      border-color: rgba(218, 165, 32, 0.8);
      box-shadow: 0 0 0 2px rgba(218, 165, 32, 0.3);
    }
  }
}

.watch-delete-action {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  width: 132rpx;
  display: flex;
  align-items: stretch;
  justify-content: flex-end;
  opacity: 0.18;
  transform: scale(0.95);
  transform-origin: right center;
  transition: opacity 0.28s ease, transform 0.28s cubic-bezier(0.22, 0.8, 0.24, 1);

  .watch-swipe-item.is-deleting & {
    opacity: 0;
    transform: translate3d(16rpx, 0, 0) scale(0.9);
    transition: opacity 0.18s ease, transform 0.2s ease;
  }
}

.watch-delete-btn {
  width: 132rpx;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(180deg, rgba(243, 122, 98, 0.84) 0%, rgba(223, 94, 71, 0.88) 100%);
}

.watch-delete-visual {
  width: 92rpx;
  height: 92rpx;
  opacity: var(--delete-icon-opacity, 0.35);
  transform: scale(var(--delete-icon-scale, 0.9));
  transition: opacity 0.28s ease, transform 0.28s cubic-bezier(0.22, 0.8, 0.24, 1);
}

.watch-card {
  position: relative;
  overflow: hidden;
  background:
    radial-gradient(circle at 12% 14%, rgba(255, 255, 255, 0.16), transparent 24%),
    radial-gradient(circle at 88% 16%, rgba(255, 255, 255, 0.08), transparent 22%),
    linear-gradient(180deg, #fff6e7 0%, #f7ebc9 100%);
  border: 1px solid $border-card;
  border-radius: $radius-lg;
  backdrop-filter: $glass-blur;
  -webkit-backdrop-filter: $glass-blur;
  padding: 24rpx 28rpx;
  box-shadow: $shadow-sm;
  transition: all 0.2s ease;

  &::before,
  &::after {
    content: '';
    position: absolute;
    inset: 0;
    pointer-events: none;
  }

  &::before {
    background-image:
      linear-gradient(rgba(255, 255, 255, 0.08) 1px, transparent 1px),
      linear-gradient(90deg, rgba(255, 255, 255, 0.08) 1px, transparent 1px);
    background-size: 22rpx 22rpx;
    opacity: 0.22;
  }

  &::after {
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.22), transparent 28%);
    opacity: 0.9;
  }

  &:active {
    opacity: 0.9;
  }
}

.watch-card--swipeable {
  margin-bottom: 0;
  transition: transform 0.28s cubic-bezier(0.22, 0.8, 0.24, 1), box-shadow 0.28s cubic-bezier(0.22, 0.8, 0.24, 1), opacity 0.2s ease;
  will-change: transform;
  transform: translate3d(0, 0, 0);
  backface-visibility: hidden;

  .watch-swipe-item.is-deleting & {
    opacity: 0;
    transform: translate3d(-172rpx, 0, 0) scale(0.92);
    transition: transform 0.22s cubic-bezier(0.4, 0, 0.2, 1), opacity 0.18s ease;
  }

  &.is-swipe-dragging {
    transition: none;
  }

  &.is-swipe-open {
    box-shadow: 0 16rpx 36rpx rgba(80, 49, 21, 0.16);
  }
}


.watch-card-glow,
.watch-card-glow::before,
.watch-card-glow::after {
  content: '';
  position: absolute;
  border-radius: 999rpx;
  filter: blur(56rpx);
  pointer-events: none;
}

.watch-card-glow {
  width: 300rpx;
  height: 300rpx;
  top: -56rpx;
  right: -44rpx;
