}

.watch-card-glow::before {
  width: 220rpx;
  height: 220rpx;
  left: -416rpx;
  top: 364rpx;
  background: rgba(255, 226, 160, 0.14);
}

.watch-card-glow::after {
  width: 240rpx;
  height: 240rpx;
  left: -72rpx;
  top: 728rpx;
  background: rgba(255, 188, 136, 0.10);
}

