      rgba(253, 230, 138, 0.5) 50%,
      rgba(252, 211, 77, 0.3) 100%);
    border: 1px solid rgba(217, 119, 6, 0.15);
  }
}

// 今日盈亏卡片特殊样式
.today-profit-card {
  height: 340rpx;
  min-height: 340rpx;
  
  .bento-card__content {
    background: linear-gradient(
      rgba(255, 255, 255, 0.5),
      rgba(200, 200, 200, 0.3)
    );
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    position: absolute;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    border-radius: $radius-lg;
    padding: 28rpx;
    box-sizing: border-box;
    // display: flex;
    // flex-direction: column;
    z-index: 1;
  }
}

.blob {
  position: absolute;
  z-index: 0;
  border-radius: 5em;
  width: 200rpx;
  height: 200rpx;
  opacity: 0.6;
  filter: blur(60rpx);
}

.stock-lottie-canvas {
  position: absolute;
  bottom: 0rpx;
  right: 8rpx;
  left: -8rpx;
  width: 350rpx;
  height: 140rpx;
  z-index: 10;
}

.blob1 {
  left: -50rpx;
  top: -90rpx;
  background: #fbbf24;
}

.blob2 {
  left: 110rpx;
  top: -20rpx;
  background: #f97316;
}

.blob3 {
  left: -40rpx;
  top: 100rpx;
  background: #ef4444;
}

.blob4 {
  left: 100rpx;
  top: 180rpx;
  background: #fcd34d;
}

// 累计收益金属卡片样式
.total-profit-card {
  height: 340rpx;
  min-height: 240rpx;
  background-image: linear-gradient(to right bottom, #252324, #292728, #2d2c2d, #313031, #353535);
  box-shadow: 7px 7px 10px rgba(0, 0, 0, 0.307);
  padding: 0;
  position: relative;
  overflow: hidden;
}

.metal-card-top {
  position: absolute;
  width: 65%;
  height: 37%;
  top: 0;
  left: 37rpx;
  background-image: linear-gradient(to right bottom, #202020, #222222, #232323, #252525, #272727);
  z-index: 500;
  border-top: 4rpx solid #e8e8e8;
  border-right: 3rpx solid #121212;
  border-bottom: 3rpx solid #121212;
  border-left: 3rpx solid #121212;
  border-bottom-left-radius: 10rpx;
  border-bottom-right-radius: 10rpx;
}

.metal-card-plastic {
  position: absolute;
  top: 0;
  right: 32%;
  width: 25%;
  background-color: black;
  height: 82%;
  z-index: 1000;
  border-top: 30rpx solid white;
}

.metal-card-bottom {
  z-index: 1000;
  position: absolute;
  bottom: 1rpx;
  right: 50%;
  transform: translate(50%, 0);
  width: 75%;
  height: 52%;
  background-color: #ecebe0;
  border-top-left-radius: 5rpx;
  border-top-right-radius: 5rpx;
  border-top: 3rpx solid #121212;
  border-left: 3rpx solid #121212;
  border-right: 3rpx solid #121212;
  border-radius: 10rpx;
}

.metal-card-metal {
  z-index: 2000;
  position: absolute;
  top: -3rpx;
  right: 0;
  width: 77%;
  height: 103%;
  background-image: linear-gradient(to right bottom, #bdbdbd, #cacaca, #d7d7d7, #e5e5e5, #f2f2f2);
  border-bottom-left-radius: 10rpx;
  border-bottom-right-radius: 10rpx;
  clip-path: polygon(0% 0%, 0% 100%, 60% 100%, 60% 18%, 85% 18%, 85% 93%, 25% 93%, 25% 100%, 100% 100%, 100% 0%);
  animation: metalSlide 3s ease-in-out infinite;
}

@keyframes metalSlide {
  0%, 100% { transform: translateX(0); }
  50% { transform: translateX(-44rpx); }
}

.metal-card-minicuadro1 {
  bottom: 12rpx;
  right: 12rpx;
  position: absolute;
  width: 20rpx;
  height: 20rpx;
  background-color: #d7d7d7;
  border: 1rpx solid #191919;
}

.metal-card-minicuadro2 {
  bottom: 12rpx;
  left: 12rpx;
  position: absolute;
  width: 20rpx;
  height: 20rpx;
  background-image: linear-gradient(to right bottom, #191919, #202020, #272727, #2e2e2e, #353535);
  border: 1rpx solid #191919;
}

.metal-card-yellow {
  position: absolute;
  bottom: 0;
  width: 100%;
  height: 8rpx;
  background-color: rgb(255, 157, 0);
}

.metal-card-content {
  position: absolute;
  top: 8rpx;
  left: 16rpx;
  right: 16rpx;
  z-index: 10;
}

.metal-card-label {
  font-size: 28rpx;
  color: $text-primary;
  font-weight: bold;
  text-transform: uppercase;
  display: block;
  margin-top: 10rpx;
  margin-bottom: 14rpx;
}

.metal-card-value {
  font-size: 28rpx;
  font-weight: 800;
  letter-spacing: -1rpx;
  line-height: 24rpx;
  display: block;
  margin-bottom: 10rpx;
  
  &.red { color: #dc2626; }
  &.green { color: #16a34a; }
}

.metal-card-badge {
  display: inline-flex;
  align-items: center;
  gap: 4rpx;
  padding: 4rpx 10rpx;
  border-radius: 16rpx;
  font-size: 18rpx;
  font-weight: 700;
  width: fit-content;
  
  &.up { background: rgba(220, 38, 38, 0.15); color: #dc2626; }
  &.down { background: rgba(22, 163, 74, 0.15); color: #16a34a; }
}

.metal-card-arrow {
  width: 16rpx;
  height: 16rpx;
}


.card-label {
  font-size: 22rpx;
  // color: $text-tertiary;
  color: $text-primary;
  margin-bottom: 16rpx;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1rpx;
  display: block;
}

.card-value {
  font-size: 48rpx;
  font-weight: 800;
  letter-spacing: -2rpx;
  line-height: 1.1;
  display: block;
  word-break: break-all;
  
  &.large {
    font-size: 64rpx;
    color: $accent-terracotta;
  }
  
  &.green { color: $accent-green; }
  &.red { color: $accent-red; }
}

.card-sub {
  font-size: 24rpx;
  color: $text-secondary;
  margin-top: 16rpx;
  display: block;
}

.stat-pills {
  display: flex;
  flex-wrap: wrap;
  gap: 16rpx;
  margin-top: 24rpx;
}

.stat-pill {
  display: flex;
  align-items: center;
  gap: 8rpx;
  padding: 16rpx 24rpx;
  background: rgba(255, 255, 255, 0.8);
  border-radius: 40rpx;
  font-size: 24rpx;
  font-weight: 700;
  color: $text-secondary;
  border: 1px solid $border-card;
  
  &.up {
    background: rgba(220, 38, 38, 0.1);
    color: $accent-red;
    border-color: rgba(220, 38, 38, 0.2);
  }
  
  &.down {
    background: rgba(5, 150, 105, 0.1);
    color: $accent-green;
    border-color: rgba(5, 150, 105, 0.2);
  }
  
  .arrow {
    font-size: 22rpx;
  }
  
  .arrow-svg {
    width: 28rpx;
    height: 28rpx;
  }
}

.today-badge {
  display: inline-flex;
  align-items: center;
  gap: 6rpx;
  padding: 10rpx 20rpx;
  border-radius: 40rpx;
  font-size: 22rpx;
  font-weight: 700;
  margin-top: 16rpx;
  white-space: nowrap;
  background: rgb(255 255 255 / 30%);
  
  &.up {
    // background: rgba(220, 38, 38, 0.12);
    color: $accent-red;
  }
  
  &.down {
    // background: rgba(5, 150, 105, 0.12);
    color: $accent-green;
  }
  
  .arrow {
    font-size: 18rpx;
  }
  
  .arrow-svg {
    width: 20rpx;
    height: 20rpx;
  }
}

.section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24rpx;
  position: relative;
  z-index: 10;
  flex-shrink: 0;
  gap: 16rpx;
}

.section-title {
  font-size: 32rpx;
  font-weight: 600;
  color: $text-primary;
  flex-shrink: 0;
}

// 收起/展开按钮（在section-header中）
.collapse-btn {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 56rpx;
  max-width: 120rpx;
  background: rgba(180, 130, 70, 0.08);
  border-radius: 28rpx;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  
  &:active {
    transform: scale(0.95);
    background: rgba(180, 130, 70, 0.15);
  }
}

.rollup-lottie-canvas {
  width: 40rpx;
  height: 40rpx;
  transition: transform 0.7s cubic-bezier(0.4, 0, 0.2, 1);
  transform-origin: center center;
  will-change: transform;
}

.sort-control {
  display: flex;
  align-items: center;
  gap: 12rpx;
}

.sort-picker {
  display: flex;
  align-items: center;
  gap: 8rpx;
  padding: 12rpx 20rpx;
  background: rgba(255, 255, 255, 0.5);
  border-radius: 24rpx;
  border: 1px solid rgba(180, 130, 70, 0.2);
}

.sort-label {
  font-size: 24rpx;
  color: $text-secondary;
}

.sort-arrow {
  font-size: 18rpx;
  color: $text-tertiary;
  transition: transform 0.2s ease;

  &--open {
    transform: rotate(180deg);
  }
}

.sort-dropdown-mask {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 199;
}

.sort-dropdown-glass {
  position: fixed;
  min-width: 240rpx;
  background: transparent;
  backdrop-filter: blur(40px) saturate(180%);
  -webkit-backdrop-filter: blur(40px) saturate(180%);
  border-radius: 20rpx;
  z-index: 200;
  animation: sortDropdownIn 0.2s ease-out;
  overflow: hidden;
}

.sort-dropdown {
  background: rgba(255, 255, 255, 0.15);
  padding: 8rpx 0;
  border-radius: 20rpx;
}

.sort-dropdown-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20rpx 28rpx;

  &:active {
    background: rgba(180, 130, 70, 0.1);
  }

  &--active {
    .sort-dropdown-text {
      color: #B45309;
      font-weight: 600;
    }
  }
}

.sort-dropdown-text {
  font-size: 26rpx;
  color: $text-primary;
}

@keyframes sortDropdownIn {
  from {
    opacity: 0;
    transform: translateY(-8rpx) scale(0.95);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.sort-order-btn {
  width: 56rpx;
  height: 56rpx;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(255, 255, 255, 0.5);
  border-radius: 16rpx;
  border: 1px solid rgba(180, 130, 70, 0.2);
  
  &:active {
    transform: scale(0.95);
    opacity: 0.8;
  }
}

.sort-icon {
  width: 32rpx;
  height: 32rpx;
}

.delete-all-btn {
  display: flex;
  align-items: center;
  justify-content: center;

  &:active {
    opacity: 0.7;
  }
}

.delete-all-icon {
  width: 48rpx;
  height: 48rpx;
}

// 板块筛选Tab区域
.sector-tabs-wrapper {
  position: relative;
  z-index: 9;
  margin-bottom: 20rpx;
  flex-shrink: 0;
}

.sector-tabs-scroll {
  width: 100%;
  height: auto;
}

.sector-tabs {
  display: flex;
  gap: 12rpx;
  padding: 12rpx 0;
  align-items: center;
  flex-wrap: wrap;
}

.sector-tab {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  gap: 8rpx;
  min-width: 100rpx;
  height: 56rpx;
  padding: 8rpx 16rpx;
  background: rgba(255, 255, 255, 0.4);
  border: 1px solid rgba(180, 130, 70, 0.15);
  border-radius: $radius-md;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  flex-shrink: 0;

  &:active {
    transform: scale(0.95);
  }

  &--active {
    background: linear-gradient(135deg, rgba($accent-gold, 0.3), rgba($accent-amber, 0.2));
    border-color: rgba($accent-gold, 0.4);
    box-shadow: 0 4rpx 12rpx rgba($accent-gold, 0.15);

    .sector-tab-name {
      color: $accent-gold;
      font-weight: 600;
    }

    .sector-tab-count {
      color: $accent-gold;
      font-weight: 700;
    }
  }
}

.sector-tab-name {
  font-size: 24rpx;
  color: $text-primary;
  font-weight: 500;
  transition: all 0.2s ease;
  white-space: nowrap;
  flex-shrink: 0;
}

.sector-tab-count {
  font-size: 20rpx;
  color: $text-tertiary;
  font-weight: 600;
  transition: all 0.2s ease;
  flex-shrink: 0;
}

.section-action {
  font-size: 26rpx;
  color: $text-tertiary;
}

.holding-list {
  position: relative;
  z-index: 10;
  flex: 1;
  min-height: 0; // 关键：允许flex子项收缩
  overflow: hidden;
  
  // 当统计卡片折叠时，增加持仓列表的可用空间
  // 通过动态计算高度来优化滚动区域
}

.holding-card {
  // background: $glass-bg;
  background: rgba(105, 13, 197, 0.103);
  border: 1px solid $border-card;
  border-radius: $radius-lg;
  backdrop-filter: $glass-blur;
  -webkit-backdrop-filter: $glass-blur;
  padding: 28rpx 32rpx;
  margin-bottom: 32rpx;
  box-shadow: $shadow-sm;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  transition: border-color 0.3s ease, box-shadow 0.3s ease;

  &--key-match {
    border-color: rgba(218, 165, 32, 0.8);
    box-shadow: 0 0 0 2px rgba(218, 165, 32, 0.3), $shadow-sm;
  }
}

.submit-btn {
  display: flex;
  justify-content: center;
  align-items: center;
  width: calc(100% + 64rpx);
  border-radius: 0 0 30rpx 30rpx;
  overflow: hidden;
  margin-top: 20rpx;
  margin-left: -32rpx;
  margin-right: -32rpx;
  margin-bottom: -32rpx;
  background: rgba(247, 234, 234, 0.3);
  gap: 0;
}

.action-btn {
  border: none;
  flex: 1;
  height: 60rpx;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: rgba(247, 234, 234, 0.589);
}

.action-text {
  font-size: 24rpx;
  font-weight: 600;
  color: $text-secondary;
}

.action-icon {
  width: 38rpx;
  height: 38rpx;
}

.holding-name-row {
  margin-bottom: 16rpx;
  padding-bottom: 12rpx;
  border-bottom: 1px solid rgba(180, 130, 70, 0.1);
}

.holding-row-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16rpx;
}

.holding-row-profit,
.holding-row-today {
  display: flex;
  align-items: center;
  gap: 8rpx;
  margin-bottom: 8rpx;
}

.stat-label {
  font-size: 22rpx;
  color: $text-tertiary;
  flex-shrink: 0;
}

.holding-name {
  font-size: 32rpx;
  font-weight: 700;
  color: $text-primary;
}

.holding-amount {
  font-size: 24rpx;
  color: $text-secondary;
  flex-shrink: 0;
}

.code-sector-row {
  display: flex;
  align-items: center;
  gap: 12rpx;
  flex-wrap: wrap;
  width: 100%;
  min-width: 0;
  overflow: hidden;
}

.holding-code {
  font-size: 20rpx;
  color: $text-tertiary;
  background: rgba(180, 130, 70, 0.08);
  padding: 6rpx 16rpx;
  border-radius: 12rpx;
}

.sector-row {
  display: flex;
  align-items: center;
  gap: 12rpx;
  flex-wrap: wrap;
}

.sector-tag {
  font-size: 20rpx;
  color: $accent-terracotta;
  background: rgba(217, 119, 6, 0.1);
  padding: 6rpx 14rpx;
  border-radius: 8rpx;
  border: 1px solid rgba(217, 119, 6, 0.2);
}

.detailed-sector-row {
  display: flex;
  align-items: center;
  gap: 12rpx;
  flex-wrap: wrap;
  margin-top: 6rpx;
}

.detailed-sector-tag {
  font-size: 22rpx;
  color: #059669;
  background: rgba(5, 150, 105, 0.1);
  padding: 6rpx 14rpx;
  border-radius: 8rpx;
  border: 1px solid rgba(5, 150, 105, 0.2);
  font-weight: 500;
}

.stat-icon {
  font-size: 22rpx;
  width: 32rpx;
  text-align: center;
}

.stat-icon-svg {
  width: 36rpx;
  height: 36rpx;
}

.stat-icon-moneybag {
  width: 40rpx;
  height: 30rpx;
}

.stat-value {
  font-size: 28rpx;
  font-weight: 700;
  min-width: 100rpx;
  text-align: right;
  
  &.green { color: $accent-green; }
  &.red { color: $accent-red; }
}

.stat-rate {
  font-size: 22rpx;
  font-weight: 600;
  
  &.green { color: $accent-green; }
  &.red { color: $accent-red; }
}

.estimate-time {
  font-size: 18rpx;
  color: $text-tertiary;
  margin-left: 8rpx;
  padding: 2rpx 8rpx;
  background: rgba(0, 0, 0, 0.05);
  border-radius: 4rpx;
}

.holding-row-note {
  display: flex;
  align-items: flex-start;
  gap: 6rpx;
  margin-top: 12rpx;
  padding: 12rpx 16rpx;
  background: rgba(217, 119, 6, 0.06);
  border-left: 4rpx solid $accent-amber;
  border-radius: 8rpx;
}

.note-label {
  font-size: 22rpx;
  color: $accent-terracotta;
  font-weight: 600;
  flex-shrink: 0;
}

.note-text {
  font-size: 24rpx;
  color: $text-primary;
  line-height: 1.5;
  word-break: break-all;
  flex: 1;
}

.empty-state {
  text-align: center;
  padding: 100rpx 40rpx;
}

.empty-icon {
  font-size: 100rpx;
  margin-bottom: 24rpx;
}

.empty-icon-svg {
  width: 120rpx;
  height: 120rpx;
  margin: 0 auto 24rpx;
  display: block;
}

.empty-text {
  font-size: 28rpx;
  color: $text-secondary;
  display: block;
  margin-bottom: 12rpx;
}

.empty-hint {
  font-size: 24rpx;
  color: $text-tertiary;
}

.fab {
  position: fixed;
  bottom: 180rpx;
  right: 32rpx;
  width: 100rpx;
  height: 100rpx;
  z-index: 100;
  
  &:active {
    transform: scale(0.9);
  }
}

.fab-icon-svg {
  width: 100rpx;
  height: 100rpx;
}

.search-fab {
  width: 64rpx;
  height: 64rpx;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-right: 8rpx;

  &:active {
    transform: scale(0.9);
  }
}

.search-lottie-canvas {
  width: 56rpx;
  height: 56rpx;
}

.search-fab-input {
  position: fixed;
  left: -9999rpx;
  top: -9999rpx;
  width: 0;
  height: 0;
  opacity: 0;
}

.nav-placeholder {
  height: 120rpx;
}

.key-input-hint {
  position: fixed;
  bottom: 300rpx;
  left: 50%;
  transform: translateX(-50%);
  background: rgba(30, 30, 40, 0.85);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-radius: 20rpx;
  padding: 16rpx 32rpx;
  z-index: 200;
  animation: keyHintIn 0.2s ease-out;

  &--match {
    background: rgba(180, 130, 20, 0.85);
  }
}

.key-input-hint-text {
  font-size: 28rpx;
  color: #fff;
  font-family: 'SF Mono', 'Menlo', 'Consolas', monospace;
  letter-spacing: 2rpx;
}

@keyframes keyHintIn {
  from {
    opacity: 0;
    transform: translateX(-50%) translateY(20rpx);
  }
  to {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }
}

.modal-mask {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(255, 255, 255, 0.3);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  animation: fadeIn 0.2s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.modal-container {
  width: 580rpx;
  background: #fffcf5;
  box-shadow: none;
  border-radius: 40rpx;
  padding: 48rpx 40rpx 40rpx;
  display: flex;
  flex-direction: column;
  align-items: center;
  animation: slideUp 0.3s ease;
}

@keyframes slideUp {
  from { 
    opacity: 0;
    transform: translateY(40rpx) scale(0.95);
  }
  to { 
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.modal-icon {
  width: 100rpx;
